// Importing external libraries and internal modules
import express, { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { validateCreateGroup, validateLinkTelegram } from './group.validator';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';
import { AppError } from '../../middlewares/error-handler';
import { successResponse } from '../../utils/response';

export class GroupController {
  private groupService: GroupService;

  constructor(groupService: GroupService) {
    this.groupService = groupService;
  }

  async createGroup(req: Request, res: Response, next: NextFunction) {
    try {
      const validatedData = validateCreateGroup(req.body);
      const createGroupDTO: CreateGroupDTO = {
        name: validatedData.name,
        description: validatedData.description,
        adminId: req.user.id
      };
      const group = await this.groupService.createGroup(createGroupDTO);
      successResponse(res, group);
    } catch (error) {
      next(error);
    }
  }

  async linkTelegram(req: Request, res: Response, next: NextFunction) {
    try {
      const validatedData = validateLinkTelegram(req.body);
      const linkTelegramDTO: LinkTelegramDTO = {
        groupId: req.params.id,
        telegramChatId: validatedData.telegramChatId,
        userId: req.user.id
      };
      const group = await this.groupService.linkTelegram(linkTelegramDTO);
      successResponse(res, group);
    } catch (error) {
      next(error);
    }
  }
}

// Importing necessary repositories and DTOs
import { GroupRepository } from './group.repository';
import { CreateGroupDTO, LinkTelegramDTO } from './group.dto';
import { AppError } from '../../middlewares/error-handler';

export class GroupService {
  constructor(private groupRepository: GroupRepository) {}

  async createGroup(dto: CreateGroupDTO) {
    return await this.groupRepository.create(dto);
  }

  async linkTelegram(dto: LinkTelegramDTO) {
    const group = await this.groupRepository.findById(dto.groupId);
    if (!group) {
      throw new AppError('Group not found', 'GROUP_NOT_FOUND', 404);
    }
    if (group.adminId.toString() !== dto.userId) {
      throw new AppError('Unauthorized operation', 'UNAUTHORIZED', 403);
    }
    return await this.groupRepository.updateTelegramChatId(dto.groupId, dto.telegramChatId);
  }
}

// Import necessary modules and database connector
import { Group } from './group.model';
import { ObjectId } from 'mongodb';

export class GroupRepository {
  async create(groupData: { name: string, description: string, adminId: ObjectId }) {
    const group = new Group(groupData);
    await group.save();
    return group;
  }

  async findById(groupId: string) {
    return await Group.findById(new ObjectId(groupId));
  }

  async updateTelegramChatId(groupId: string, telegramChatId: string) {
    return await Group.findByIdAndUpdate(new ObjectId(groupId), { telegramChatId }, { new: true });
  }
}

// Import mongoose for MongoDB interaction
import mongoose, { Schema, Document } from 'mongoose';

interface GroupDocument extends Document {
  name: string;
  description: string;
  adminId: mongoose.Types.ObjectId;
  members: mongoose.Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const GroupSchema: Schema = new Schema({
  name: { type: String, required: true },
  description: { type: String, required: true },
  adminId: { type: mongoose.Types.ObjectId, required: true },
  members: [{ type: mongoose.Types.ObjectId }],
  telegramChatId: { type: String },
  createdAt: { type: Date, default: Date.now }
});

export const Group = mongoose.model<GroupDocument>('Group', GroupSchema);

// Define DTOs for request and response
type CreateGroupDTO = {
  name: string;
  description: string;
  adminId: string;
};

type LinkTelegramDTO = {
  groupId: string;
  telegramChatId: string;
  userId: string;
};

export { CreateGroupDTO, LinkTelegramDTO };

// Import Zod for validation
import { z } from 'zod';

const createGroupSchema = z.object({
  name: z.string().min(1, "Group name is required"),
  description: z.string().min(1, "Description is required")
});

const linkTelegramSchema = z.object({
  telegramChatId: z.string().min(1, "Telegram Chat ID is required")
});

export function validateCreateGroup(data: any) {
  return createGroupSchema.parse(data);
}

export function validateLinkTelegram(data: any) {
  return linkTelegramSchema.parse(data);
}

// Centralized error handling middleware
import { Request, Response, NextFunction } from 'express';

class AppError extends Error {
  statusCode: number;
  code: string;

  constructor(message: string, code: string, statusCode: number = 500) {
    super(message);
    this.code = code;
    this.statusCode = statusCode;
  }
}

export function errorHandler(err: AppError, req: Request, res: Response, next: NextFunction) {
  res.status(err.statusCode || 500).json({
    success: false,
    error: {
      code: err.code || 'UNKNOWN_ERROR',
      message: err.message
    },
    meta: {
      requestId: req.headers['x-request-id'] || '',
      timestamp: new Date().toISOString(),
      version: 'v1'
    }
  });
}

export { AppError };

// Utility for success JSON responses
import { Response } from 'express';

export function successResponse(res: Response, data: any) {
  res.json({
    success: true,
    data,
    meta: {
      requestId: res.getHeader('x-request-id') || '',
      timestamp: new Date().toISOString(),
      version: 'v1',
    }
  });
}
